mapper.select:
SELECT DISTINCT c.* FROM CARDS c
LEFT JOIN CARD_KEYWORDS ck ON c.card_id = ck.card_id AND ck.deleted_yn = 'N' LEFT JOIN SEARCH_KEYWORDS sk ON ck.keyword_id = sk.keyword_id AND sk.deleted_yn = 'N'
WHERE c.card_status = 'PUBLISHED' AND c.visible_yn = 'Y' AND c.searchable_yn = 'Y' AND c.deleted_yn = 'N' AND c.publish_start_at <= SYSTIMESTAMP AND (c.publish_end_at IS NULL OR c.publish_end_at >= SYSTIMESTAMP)
AND ( c.card_name LIKE '%' || #{q} || '%' OR c.summary_description LIKE '%' || #{q} || '%' OR c.company_name LIKE '%' || #{q} || '%' OR sk.keyword LIKE '%' || #{q} || '%' )
AND c.card_type = #{cardType}
AND c.company_name LIKE '%' || #{companyName} || '%'
AND EXISTS ( SELECT 1 FROM CARD_BENEFITS cb WHERE cb.card_id = c.card_id AND cb.category_id = #{categoryId} AND cb.visible_yn = 'Y' )
AND ( SELECT COUNT(DISTINCT cb2.category_id) FROM CARD_BENEFITS cb2 WHERE cb2.card_id = c.card_id AND cb2.visible_yn = 'Y' AND cb2.category_id IN
#{cid}
) >= #{categoryCount}
AND c.annual_fee_domestic >= #{minFee}
AND c.annual_fee_domestic <= #{maxFee}
ORDER BY c.card_name ASC ORDER BY c.annual_fee_domestic ASC ORDER BY c.application_count DESC ORDER BY c.view_count DESC
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT * FROM CARDS
WHERE  card_id   = #{cardId}
  AND  deleted_yn = 'N'

SELECT DISTINCT c.* FROM CARDS c
LEFT JOIN CARD_KEYWORDS ck ON c.card_id = ck.card_id LEFT JOIN SEARCH_KEYWORDS sk ON ck.keyword_id = sk.keyword_id AND sk.deleted_yn = 'N'
WHERE c.deleted_yn = 'N'
AND c.card_name LIKE '%' || #{cardName} || '%'
AND c.company_name LIKE '%' || #{companyName} || '%'
AND c.card_type = #{cardType}
AND c.card_status = #{cardStatus}
AND c.brand_name = #{brandName}
AND c.publish_start_at >= #{publishStartFrom}
AND c.publish_start_at <= #{publishStartTo}
AND ( c.card_name LIKE '%' || #{keyword} || '%' OR c.company_name LIKE '%' || #{keyword} || '%' OR sk.keyword LIKE '%' || #{keyword} || '%' )
ORDER BY c.card_name ASC ORDER BY c.annual_fee_domestic ASC ORDER BY c.application_count DESC ORDER BY c.created_at DESC
OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

mapper.update:
UPDATE CARDS
SET    view_count = NVL(view_count, 0) + 1
WHERE  card_id = #{cardId}

UPDATE CARDS
SET    application_count = application_count + 1
WHERE  card_id = #{cardId}

UPDATE CARD_VERSIONS SET version_status = 'PUBLISHED', published_at = SYSTIMESTAMP WHERE card_id IN
#{id}
AND version_status = 'APPROVED'

UPDATE CARD_VERSIONS SET version_status = 'ARCHIVED' WHERE card_id IN
#{id}
AND version_status = 'PUBLISHED'
